(function(){
  PyLearn.createEditor({
    containerId: 'editor-prac-print',
    initialCode: 'username = "alice"
role = "admin"
attempts = 0

# Print all three lines using commas
',
    label: 'Practice 1',
    validate: async function(output, error, code) {
      if (error) return { pass: false, message: '\u274c Error: ' + error };
      var expected = 'User: alice\nRole: admin\nAttempts: 0';
      if (output.trim() !== expected) {
        var lines = output.trim().split('\n');
        if (lines.length < 3) return { pass: false, message: '\u274c Expected 3 lines, got ' + lines.length + '.' };
        return { pass: false, message: '\u274c Output doesn\'t match. Check your labels and spacing.' };
      }
      if (/"alice"/.test(code) && !/username/.test(code.split('=').slice(1).join('='))) return { pass: false, message: '\u26a0\ufe0f Use the variable names, not the literal values.' };
      return { pass: true, message: '\u2705 Perfect — three lines, comma-separated print.' };
    },
    onPass: async function() { await window.__markStepComplete(); }
  });
})();

(function(){
  PyLearn.createEditor({
    containerId: 'editor-prac-sel',
    initialCode: 'role = "admin"  # try changing to "user" or "guest"\n\n# Write your if/elif/else here\n',
    label: 'Practice 2',
    validate: async function(output, error, code) {
      if (error) return { pass: false, message: '\u274c Error: ' + error };
      // Run silently with all three roles to verify
      var cases = [
        { role: 'admin',  expected: 'Full access' },
        { role: 'user',   expected: 'Standard access' },
        { role: 'guest',  expected: 'No access' },
        { role: 'random', expected: 'No access' },
      ];
      var stripped = code.replace(/^role\s*=.*$/m, '');
      for (var i = 0; i < cases.length; i++) {
        var c = cases[i];
        var testCode = 'role = "' + c.role + '"\n' + stripped;
        var r = await PyLearn.runPython(testCode);
        if (r.error) return { pass: false, message: '\u274c Error when role="' + c.role + '": ' + r.error };
        if (r.output.trim() !== c.expected) {
          return { pass: false, message: '\u274c When role="' + c.role + '": got "' + r.output.trim() + '" but expected "' + c.expected + '".' };
        }
      }
      return { pass: true, message: '\u2705 All cases correct!' };
    },
    onPass: async function() { await window.__markStepComplete(); }
  });
})();

