(function(){
  var VALIDATOR_FN = 'def check_password(username, password):\n    accounts = {"alice": "Sunshine7", "bob": "Football3", "admin": "Adm1n!Pass", "guest": "guest"}\n    if username not in accounts:\n        return False\n    return accounts[username] == password\n';

  var wrap = document.getElementById('editor-login');
  PyLearn.createEditor({
    containerId: 'editor-login',
    initialCode: VALIDATOR_FN + '\nusername = input("Username: ")\npassword = input("Password: ")\n\n# Call check_password and print Access granted or Access denied\n',
    label: 'Login Screen',
    validate: async function(output, error, code) {
      if (error) return { pass: false, message: '\u274c Error: ' + error };

      // Test 1: valid login
      var r1 = await PyLearn.runPython(code, (function(){
        var q = ['alice', 'Sunshine7'];
        return async function() { return q.shift() || ''; };
      })());
      if (r1.error) return { pass: false, message: '\u274c Error on valid login: ' + r1.error };
      if (r1.output.trim() !== 'Access granted') return { pass: false, message: '\u274c With alice/Sunshine7 expected "Access granted" but got: "' + r1.output.trim() + '".' };

      // Test 2: wrong password
      var r2 = await PyLearn.runPython(code, (function(){
        var q = ['alice', 'wrongpass'];
        return async function() { return q.shift() || ''; };
      })());
      if (r2.error) return { pass: false, message: '\u274c Error on bad login: ' + r2.error };
      if (r2.output.trim() !== 'Access denied') return { pass: false, message: '\u274c With alice/wrongpass expected "Access denied" but got: "' + r2.output.trim() + '".' };

      // Test 3: unknown user
      var r3 = await PyLearn.runPython(code, (function(){
        var q = ['nobody', 'anything'];
        return async function() { return q.shift() || ''; };
      })());
      if (r3.error) return { pass: false, message: '\u274c Error on unknown user: ' + r3.error };
      if (r3.output.trim() !== 'Access denied') return { pass: false, message: '\u274c With unknown user expected "Access denied" but got: "' + r3.output.trim() + '".' };

      return { pass: true, message: '\u2705 Login screen works perfectly. All three cases passed.' };
    },
    onPass: async function() { await window.__markStepComplete(); }
  });

  // Supply simulated input for the visible Run button
  var runBtn = wrap.querySelector('.pylearn-btn-run');
  runBtn.onclick = null;
  runBtn.addEventListener('click', async function() {
    runBtn.disabled = true;
    var code = wrap.querySelector('.pylearn-code-area').value;
    var answers = ['alice', 'Sunshine7'];
    var r = await PyLearn.runPython(code, async function() { return answers.shift() || ''; });
    var out = wrap.querySelector('.pylearn-output-area');
    if (out) { out.textContent = (r.output || '') + (r.error || ''); out.classList.toggle('has-error', !!r.error); }
    runBtn.disabled = false;
  });
})();

(function(){
  var VALIDATOR_FN = 'def check_password(username, password):\n    accounts = {"alice": "Sunshine7", "bob": "Football3", "admin": "Adm1n!Pass", "guest": "guest"}\n    if username not in accounts:\n        return False\n    return accounts[username] == password\n';

  var streak = 0;
  var best   = parseInt(localStorage.getItem('pylearn_login_best') || '0', 10);
  document.getElementById('el-best').textContent = best;

  // ── Challenge bank ─────────────────────────────────────────
  // Each challenge: { prompt, note, inputs[], tests[] }
  // tests[]: { inputs[], expected string in output }
  var challenges = [

    {
      prompt: 'Print the following two lines using variables and commas only (no string formatting):<br><code>System: PyLearn</code><br><code>Version: 3</code>',
      note: '',
      inputs: [],
      check: async function(code) {
        var r = await PyLearn.runPython(code);
        if (r.error) return '\u274c ' + r.error;
        var expected = 'System: PyLearn\nVersion: 3';
        if (r.output.trim() !== expected) return '\u274c Output doesn\'t match. Got: ' + r.output.trim();
        return null;
      }
    },

    {
      prompt: 'Declare three variables: <code>city = "London"</code>, <code>country = "UK"</code>, <code>population = 9000000</code>. Print one line: <code>City: London, UK (pop: 9000000)</code> using commas only.',
      note: '',
      inputs: [],
      check: async function(code) {
        var r = await PyLearn.runPython(code);
        if (r.error) return '\u274c ' + r.error;
        if (r.output.trim() !== 'City: London, UK (pop: 9000000)') return '\u274c Got: "' + r.output.trim() + '"';
        return null;
      }
    },

    {
      prompt: 'Ask the user for their <code>favourite colour</code> (prompt: <code>"Favourite colour: "</code>). Print: <code>You chose: &lt;colour&gt;</code>',
      note: '&#128161; Simulated input: <strong>Blue</strong>',
      inputs: ['Blue'],
      check: async function(code) {
        var ans = ['Blue'];
        var r = await PyLearn.runPython(code, async function() { return ans.shift() || ''; });
        if (r.error) return '\u274c ' + r.error;
        if (r.output.trim() !== 'You chose: Blue') return '\u274c Got: "' + r.output.trim() + '"';
        return null;
      }
    },

    {
      prompt: 'Ask for a <code>city</code> (prompt: <code>"City: "</code>) and a <code>country</code> (prompt: <code>"Country: "</code>). Print: <code>Location: Paris, France</code>',
      note: '&#128161; Simulated inputs: <strong>Paris</strong> then <strong>France</strong>',
      inputs: ['Paris', 'France'],
      check: async function(code) {
        var ans = ['Paris', 'France'];
        var r = await PyLearn.runPython(code, async function() { return ans.shift() || ''; });
        if (r.error) return '\u274c ' + r.error;
        if (r.output.trim() !== 'Location: Paris, France') return '\u274c Got: "' + r.output.trim() + '"';
        return null;
      }
    },

    {
      prompt: 'A variable <code>score = 72</code> is defined. Print <code>Pass</code> if score &gt;= 50, otherwise print <code>Fail</code>. Test passes with score 72 (Pass) and score 30 (Fail).',
      note: '',
      inputs: [],
      check: async function(code) {
        var stripped = code.replace(/^score\s*=.*$/m, '');
        var r1 = await PyLearn.runPython('score = 72\n' + stripped);
        if (r1.error) return '\u274c Error: ' + r1.error;
        if (r1.output.trim() !== 'Pass') return '\u274c With score=72 expected Pass, got: ' + r1.output.trim();
        var r2 = await PyLearn.runPython('score = 30\n' + stripped);
        if (r2.error) return '\u274c Error: ' + r2.error;
        if (r2.output.trim() !== 'Fail') return '\u274c With score=30 expected Fail, got: ' + r2.output.trim();
        return null;
      }
    },

    {
      prompt: 'A variable <code>hour = 14</code>. Print <code>Good morning</code> if hour &lt; 12, <code>Good afternoon</code> if 12 &lt;= hour &lt; 18, otherwise <code>Good evening</code>.',
      note: '',
      inputs: [],
      check: async function(code) {
        var stripped = code.replace(/^hour\s*=.*$/m, '');
        var cases = [{h:9,e:'Good morning'},{h:14,e:'Good afternoon'},{h:20,e:'Good evening'}];
        for (var i=0;i<cases.length;i++) {
          var c = cases[i];
          var r = await PyLearn.runPython('hour = ' + c.h + '\n' + stripped);
          if (r.error) return '\u274c Error (hour=' + c.h + '): ' + r.error;
          if (r.output.trim() !== c.e) return '\u274c hour=' + c.h + ': expected "' + c.e + '", got "' + r.output.trim() + '".';
        }
        return null;
      }
    },

    {
      prompt: 'Ask the user for a number (prompt: <code>"Number: "</code>). Convert it to an integer with <code>int()</code>. Print <code>Positive</code>, <code>Negative</code>, or <code>Zero</code>.',
      note: '&#128161; Simulated input: <strong>7</strong> (validator also tests -3 and 0)',
      inputs: ['7'],
      check: async function(code) {
        var cases = [{i:'7',e:'Positive'},{i:'-3',e:'Negative'},{i:'0',e:'Zero'}];
        for (var i=0;i<cases.length;i++) {
          var c = cases[i];
          var ans = [c.i];
          var r = await PyLearn.runPython(code, async function() { return ans.shift() || ''; });
          if (r.error) return '\u274c Error (input=' + c.i + '): ' + r.error;
          if (r.output.trim() !== c.e) return '\u274c Input ' + c.i + ': expected "' + c.e + '", got "' + r.output.trim() + '".';
        }
        return null;
      }
    },

    {
      prompt: 'Use the provided <code>check_password</code> function. Ask for a username and password. Print <code>Welcome back, &lt;username&gt;</code> on success, or <code>Login failed</code> on failure. Use commas in print.',
      note: '&#128161; Simulated inputs: <strong>bob</strong> then <strong>Football3</strong>. Validator also tests a wrong password.',
      inputs: ['bob', 'Football3'],
      check: async function(code) {
        var fullCode = VALIDATOR_FN + '\n' + code.replace(/def check_password[\s\S]*?\breturn\b[^\n]*\n/g, '');
        // Test correct
        var r1 = await PyLearn.runPython(fullCode, (function(){ var q=['bob','Football3']; return async function(){ return q.shift()||''; }; })());
        if (r1.error) return '\u274c Error: ' + r1.error;
        if (r1.output.trim() !== 'Welcome back, bob') return '\u274c Correct login: expected "Welcome back, bob", got "' + r1.output.trim() + '".';
        // Test wrong
        var r2 = await PyLearn.runPython(fullCode, (function(){ var q=['bob','wrongpass']; return async function(){ return q.shift()||''; }; })());
        if (r2.error) return '\u274c Error: ' + r2.error;
        if (r2.output.trim() !== 'Login failed') return '\u274c Wrong password: expected "Login failed", got "' + r2.output.trim() + '".';
        return null;
      }
    },

    {
      prompt: 'Ask for a <code>username</code>. If username is <code>"admin"</code> print <code>Admin portal</code>, if it is <code>"guest"</code> print <code>Guest access</code>, otherwise print <code>Standard user</code>.',
      note: '&#128161; Simulated input: <strong>admin</strong>. Validator tests all three cases.',
      inputs: ['admin'],
      check: async function(code) {
        var cases = [{i:'admin',e:'Admin portal'},{i:'guest',e:'Guest access'},{i:'alice',e:'Standard user'}];
        for (var i=0;i<cases.length;i++) {
          var c = cases[i]; var ans = [c.i];
          var r = await PyLearn.runPython(code, async function() { return ans.shift() || ''; });
          if (r.error) return '\u274c Error (input='+c.i+'): ' + r.error;
          if (r.output.trim() !== c.e) return '\u274c Input "'+c.i+'": expected "'+c.e+'", got "'+r.output.trim()+'".';
        }
        return null;
      }
    },

    {
      prompt: 'Ask the user for two words (prompt 1: <code>"Word 1: "</code>, prompt 2: <code>"Word 2: "</code>). Print them on one line separated by a space using a comma in print(). Then on a second line print the total number of characters in both words combined.',
      note: '&#128161; Simulated inputs: <strong>hello</strong> then <strong>world</strong>',
      inputs: ['hello', 'world'],
      check: async function(code) {
        var ans = ['hello', 'world'];
        var r = await PyLearn.runPython(code, async function() { return ans.shift() || ''; });
        if (r.error) return '\u274c ' + r.error;
        var lines = r.output.trim().split('\n');
        if (lines[0].trim() !== 'hello world') return '\u274c First line should be "hello world", got: "' + (lines[0]||'').trim() + '".';
        if (lines[1] && lines[1].trim() !== '10') return '\u274c Second line should be 10 (5+5), got: "' + (lines[1]||'').trim() + '".';
        if (!lines[1]) return '\u274c Missing second line with character count.';
        return null;
      }
    }

  ];

  var currentIdx = -1;

  function pickChallenge() {
    var next;
    do { next = Math.floor(Math.random() * challenges.length); } while (next === currentIdx && challenges.length > 1);
    currentIdx = next;
    return challenges[next];
  }

  function loadChallenge() {
    var ch = pickChallenge();
    document.getElementById('el-prompt').innerHTML = ch.prompt;
    document.getElementById('el-sim-note').innerHTML = ch.note || '';

    var wrap = document.getElementById('editor-endless');
    wrap.innerHTML = '';

    PyLearn.createEditor({
      containerId: 'editor-endless',
      initialCode: ch.inputs.length ? '# Simulated input(s): ' + ch.inputs.join(', ') + '\n' : '# Write your solution\n',
      label: 'Endless Mode',
      validate: async function(output, error, code) {
        if (error) return { pass: false, message: '\u274c Error: ' + error };
        var msg = await challenges[currentIdx].check(code);
        if (msg) return { pass: false, message: msg };
        return { pass: true, message: '\u2705 Correct! Loading next challenge\u2026' };
      },
      onPass: async function() {
        streak++;
        if (streak > best) {
          best = streak;
          localStorage.setItem('pylearn_login_best', best);
          document.getElementById('el-best').textContent = best;
        }
        document.getElementById('el-streak').textContent = streak;
        setTimeout(loadChallenge, 1300);
      }
    });

    // Wire run button to supply simulated inputs
    var runBtn = wrap.querySelector('.pylearn-btn-run');
    runBtn.onclick = null;
    var capturedCh = ch;
    runBtn.addEventListener('click', async function() {
      runBtn.disabled = true;
      var code = wrap.querySelector('.pylearn-code-area').value;
      var ans = capturedCh.inputs.slice();
      var r = await PyLearn.runPython(code, async function() { return ans.shift() || ''; });
      var out = wrap.querySelector('.pylearn-output-area');
      if (out) { out.textContent = (r.output || '') + (r.error || ''); out.classList.toggle('has-error', !!r.error); }
      runBtn.disabled = false;
    });
  }

  document.getElementById('el-new').onclick = function() {
    streak = 0;
    document.getElementById('el-streak').textContent = streak;
    loadChallenge();
  };

  loadChallenge();
})();
